import Constants from 'expo-constants';
import * as SecureStore from 'expo-secure-store';
import type { StaffProfile, ProfileUpdateRequest } from '../types/api.types';

const API_URL = Constants.expoConfig?.extra?.apiUrl || 'http://localhost:3001/api';

interface DashboardData {
  teacher: {
    id: string;
    name: string;
    code: string;
    role: string;
    photo?: string;
  };
  classTeacher: {
    id: string;
    name: string;
    section: string;
  } | null;
  attendance: {
    date: string;
    status: string | null;
    inTime: string | null;
    outTime: string | null;
  };
  timetable: Array<{
    periodIndex: number;
    classId: {
      name: string;
      section: string;
    };
    subject: string;
    room: string;
  }>;
  substitutions: Array<{
    id: string;
    date: string;
    classId: {
      name: string;
      section: string;
    };
    period: string;
    absentTeacherId: {
      name: string;
    };
  }>;
  gatePasses: Array<{
    id: string;
    studentId: {
      name: string;
      rollNo: number;
    };
    date: string;
    reason: string;
  }>;
  appointments: Array<{
    id: string;
    visitorName: string;
    purpose: string;
    fromDateTime: string;
  }>;
  unreadAnnouncements: number;
}

class APIService {
  private token: string | null = null;

  async getToken() {
    if (!this.token) {
      try {
        this.token = await SecureStore.getItemAsync('user_token');
      } catch (error) {
        // If decryption fails, clear corrupted data
        if (error?.message?.includes('Could not decrypt')) {
          console.log('Clearing corrupted token...');
          await SecureStore.deleteItemAsync('user_token').catch(() => {});
          this.token = null;
        }
      }
    }
    return this.token;
  }

  async getHeaders() {
    const token = await this.getToken();
    return {
      'Content-Type': 'application/json',
      ...(token && { Authorization: `Bearer ${token}` }),
    };
  }

  private async fetchWithTimeout(url: string, options: RequestInit = {}, timeoutMs = 10000): Promise<Response> {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeoutMs);
    try {
      const response = await fetch(url, {
        ...options,
        signal: controller.signal,
      });
      clearTimeout(timeoutId);
      return response;
    } catch (error) {
      clearTimeout(timeoutId);
      throw error;
    }
  }

  async getDashboardData(teacherId: string): Promise<DashboardData> {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/dashboard`,
      { headers: await this.getHeaders() },
      30000 // Increase timeout to 30 seconds for dashboard
    );
    if (!response.ok) throw new Error('Failed to fetch dashboard data');
    return response.json();
  }

  async getTimetable(teacherId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/timetable`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch timetable');
    return response.json();
  }

  async markTeacherAttendance(teacherId: string, data: { status: string; inTime?: string; outTime?: string }) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/attendance`,
      {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify(data),
      }
    );
    if (!response.ok) throw new Error('Failed to mark attendance');
    return response.json();
  }

  async resetTeacherAttendance(teacherId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/attendance`,
      {
        method: 'DELETE',
        headers: await this.getHeaders(),
      }
    );
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || 'Failed to reset attendance');
    }
    return response.json();
  }

  async getClassStudents(teacherId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/class-students`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || `Failed to fetch class students (${response.status})`);
    }
    return response.json();
  }

  async getClassAttendance(teacherId: string, date: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/class-attendance/${date}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch class attendance');
    return response.json();
  }

  async markClassAttendance(teacherId: string, data: { date: string; attendance: Array<{ studentId: string; status: string }> }) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/class-attendance`,
      {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify(data),
      }
    );
    if (!response.ok) throw new Error('Failed to mark class attendance');
    return response.json();
  }

  async getClassOverview(teacherId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/class-overview`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch class overview');
    return response.json();
  }

  async getHomework(teacherId: string, status?: string) {
    const url = status
      ? `${API_URL}/homework/teacher/${teacherId}?status=${status}`
      : `${API_URL}/homework/teacher/${teacherId}`;
    const response = await this.fetchWithTimeout(url, { headers: await this.getHeaders() });
    if (!response.ok) throw new Error('Failed to fetch homework');
    return response.json();
  }

  async createHomework(data: {
    title: string;
    description: string;
    subject: string;
    classId: string;
    teacherId: string;
    dueDate: string;
    attachments?: Array<{ name: string; url: string; type: string }>;
  }) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/homework`,
      {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify(data),
      }
    );
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || errorData.message || 'Failed to create homework');
    }
    return response.json();
  }

  async getTeacherLeaves(teacherId: string, status?: string) {
    const url = status
      ? `${API_URL}/mobile/teacher/${teacherId}/leaves?status=${status}`
      : `${API_URL}/mobile/teacher/${teacherId}/leaves`;
    const response = await this.fetchWithTimeout(url, { headers: await this.getHeaders() });
    if (!response.ok) throw new Error('Failed to fetch leaves');
    return response.json();
  }

  async applyForLeave(data: {
    teacherId: string;
    leaveType: string;
    reason: string;
    startDate: string;
    endDate: string;
    days?: number;
    attachments?: Array<{ name: string; url: string }>;
  }) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${data.teacherId}/leaves`,
      {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify(data),
      }
    );
    if (!response.ok) throw new Error('Failed to apply for leave');
    return response.json();
  }

  async getAnnouncements(teacherId: string, limit = 20) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/announcements?limit=${limit}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch announcements');
    return response.json();
  }

  async getSubstitutions(teacherId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/substitutions?substituteTeacherId=${teacherId}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch substitutions');
    return response.json();
  }

  async getRemarks(studentId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/students/${studentId}/remarks`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch remarks');
    return response.json();
  }

  async createRemark(studentId: string, data: {
    title: string;
    description: string;
    category: string;
    sentToParent: boolean;
  }) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/students/${studentId}/remarks`,
      {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify(data),
      }
    );
    if (!response.ok) throw new Error('Failed to create remark');
    return response.json();
  }

  async getExams(classId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/exams?classId=${classId}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch exams');
    return response.json();
  }

  async createExam(data: {
    name: string;
    examType: string;
    classId: string;
    startDate: string;
    endDate: string;
    totalMarks: number;
    passingMarks: number;
    subjects: Array<{
      subjectName: string;
      date: string;
      maxMarks: number;
    }>;
  }) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/exams`,
      {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify(data),
      }
    );
    if (!response.ok) throw new Error('Failed to create exam');
    return response.json();
  }

  async getResults(examId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/results?examId=${examId}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch results');
    return response.json();
  }

  async enterMarks(examId: string, studentId: string, marks: any) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/results`,
      {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify({ examId, studentId, ...marks }),
      }
    );
    if (!response.ok) throw new Error('Failed to enter marks');
    return response.json();
  }

  async getPayslips(employeeId: string, year?: number, limit = 24, skip = 0) {
    const params = new URLSearchParams();
    if (year) params.append('year', year.toString());
    params.append('limit', limit.toString());
    params.append('skip', skip.toString());

    const response = await this.fetchWithTimeout(
      `${API_URL}/payslips/staff/${employeeId}?${params}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch payslips');
    return response.json();
  }

  async getPayslip(payslipId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/payslips/${payslipId}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch payslip');
    return response.json();
  }

  async getPayslipSummary(employeeId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/payslips/staff/${employeeId}/summary`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch payslip summary');
    return response.json();
  }

  async getStudentDetails(teacherId: string, studentId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/student/${studentId}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || errorData.message || 'Failed to fetch student details');
    }
    return response.json();
  }

  async downloadPayslip(payslipId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/payslips/${payslipId}/download`,
      {
        method: 'GET',
        headers: await this.getHeaders(),
      },
      30000 // 30 second timeout for PDF download
    );
    if (!response.ok) throw new Error('Failed to download payslip');
    return response.blob();
  }

  // Staff Profile Methods
  async getStaffProfile(staffId: string): Promise<StaffProfile> {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/staff/${staffId}/profile`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch staff profile');
    return response.json();
  }

  async updateStaffProfile(staffId: string, data: ProfileUpdateRequest): Promise<StaffProfile> {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/staff/${staffId}/profile`,
      {
        method: 'PUT',
        headers: await this.getHeaders(),
        body: JSON.stringify(data),
      }
    );
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || errorData.message || 'Failed to update staff profile');
    }
    return response.json();
  }

  async uploadProfilePhoto(staffId: string, uri: string): Promise<{ url: string }> {
    // Convert image URI to base64
    const base64Photo = await this.convertImageToBase64(uri);

    const token = await this.getToken();
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/staff/${staffId}/photo`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...(token && { Authorization: `Bearer ${token}` }),
        },
        body: JSON.stringify({ photo: base64Photo }),
      },
      30000 // 30 second timeout for photo upload
    );
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || errorData.message || 'Failed to upload photo');
    }
    return response.json();
  }

  private async convertImageToBase64(uri: string): Promise<string> {
    try {
      // Fetch the image data
      const response = await fetch(uri);
      const blob = await response.blob();

      // Convert blob to base64
      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          // Get the base64 data and add data URI prefix
          const base64 = (reader.result as string);
          resolve(base64);
        };
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });
    } catch (error) {
      throw new Error(`Failed to convert image to base64: ${error instanceof Error ? error.message : 'Unknown error'}`);
    }
  }
}

export default new APIService();

