import Constants from 'expo-constants';
import * as SecureStore from 'expo-secure-store';
import type { StaffProfile, ProfileUpdateRequest } from '../types/api.types';

const API_URL = Constants.expoConfig?.extra?.apiUrl || 'http://localhost:3001/api';

interface DashboardData {
  teacher: {
    id: string;
    name: string;
    code: string;
    role: string;
    photo?: string;
  };
  classTeacher: {
    id: string;
    name: string;
    section: string;
  } | null;
  attendance: {
    date: string;
    status: string | null;
    inTime: string | null;
    outTime: string | null;
  };
  timetable: Array<{
    periodIndex: number;
    classId: {
      name: string;
      section: string;
    };
    subject: string;
    room: string;
  }>;
  substitutions: Array<{
    id: string;
    date: string;
    classId: {
      name: string;
      section: string;
    };
    period: string;
    absentTeacherId: {
      name: string;
    };
  }>;
  gatePasses: Array<{
    id: string;
    studentId: {
      name: string;
      rollNo: number;
    };
    date: string;
    reason: string;
  }>;
  appointments: Array<{
    id: string;
    visitorName: string;
    purpose: string;
    fromDateTime: string;
  }>;
  unreadAnnouncements: number;
}

class APIService {
  private token: string | null = null;

  async getToken() {
    if (!this.token) {
      try {
        this.token = await SecureStore.getItemAsync('user_token');
      } catch (error) {
        // If decryption fails, clear corrupted data
        if (error?.message?.includes('Could not decrypt')) {
          console.log('Clearing corrupted token...');
          await SecureStore.deleteItemAsync('user_token').catch(() => {});
          this.token = null;
        }
      }
    }
    return this.token;
  }

  async getHeaders() {
    const token = await this.getToken();
    return {
      'Content-Type': 'application/json',
      ...(token && { Authorization: `Bearer ${token}` }),
    };
  }

  private async fetchWithTimeout(url: string, options: RequestInit = {}, timeoutMs = 10000): Promise<Response> {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeoutMs);
    try {
      const response = await fetch(url, {
        ...options,
        signal: controller.signal,
      });
      clearTimeout(timeoutId);
      return response;
    } catch (error) {
      clearTimeout(timeoutId);
      throw error;
    }
  }

  private async fetchWithRetry(
    url: string,
    options: RequestInit = {},
    timeoutMs = 10000,
    maxRetries = 3
  ): Promise<Response> {
    let lastError: Error | null = null;

    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        const response = await this.fetchWithTimeout(url, options, timeoutMs);

        // Don't retry on client errors (4xx)
        if (response.status >= 400 && response.status < 500) {
          return response;
        }

        // Retry on server errors (5xx) or network failures
        if (response.status >= 500 || !response.ok) {
          if (attempt < maxRetries) {
            const delay = Math.pow(2, attempt) * 1000; // Exponential backoff: 2^i * 1000ms
            await new Promise(resolve => setTimeout(resolve, delay));
            continue;
          }
        }

        return response;
      } catch (error: any) {
        lastError = error;
        // Don't retry on AbortError (timeout)
        if (error.name === 'AbortError') {
          throw error;
        }

        // Retry on network errors with exponential backoff
        if (attempt < maxRetries) {
          const delay = Math.pow(2, attempt) * 1000; // 2^i * 1000ms
          await new Promise(resolve => setTimeout(resolve, delay));
        }
      }
    }

    throw lastError || new Error('Request failed after retries');
  }

  async getDashboardData(teacherId: string): Promise<DashboardData> {
    const headers = await this.getHeaders();
    const response = await this.fetchWithRetry(
