import React, { useState, useEffect, useCallback } from 'react';
import {
  View,
  Text,
  ScrollView,
  FlatList,
  StyleSheet,
  TouchableOpacity,
  TextInput,
  Alert,
  ActivityIndicator,
} from 'react-native';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import api from '../services/api';
import { format } from 'date-fns';
import { Ionicons } from '@expo/vector-icons';
import { Stack } from 'expo-router';

export default function AttendanceScreen() {
  const { user } = useAuth();
  const { colors } = useTheme();
  const [activeTab, setActiveTab] = useState<'self' | 'class'>('self');
  const [students, setStudents] = useState<any>(null);
  const [attendance, setAttendance] = useState<any>({});
  const [loading, setLoading] = useState(false);
  const [date, setDate] = useState(format(new Date(), 'yyyy-MM-dd'));

  const loadClassStudents = useCallback(async () => {
    if (!user?.id) return;
    setLoading(true);
    try {
      const data = await api.getClassStudents(user.id);
      setStudents(data);

      // Load existing attendance
      const existingAttendance = await api.getClassAttendance(user.id, date);
      setAttendance(existingAttendance);
    } catch (error: any) {
      console.error('Error loading class students:', error);
      Alert.alert('Error', error.message || 'Failed to load students');
    } finally {
      setLoading(false);
    }
  }, [user?.id, date]);

  useEffect(() => {
    if (activeTab === 'class' && !students) {
      loadClassStudents();
    }
  }, [activeTab, students, loadClassStudents]);

  const markAttendance = useCallback((studentId: string, status: string) => {
    setAttendance((prev: any) => ({
      ...prev,
      [studentId]: status,
    }));
  }, []);

  const submitAttendance = useCallback(async () => {
    if (!user?.id || !students) return;

    const attendanceArray = students.students.map((s: any) => ({
      studentId: s.id,
      status: attendance[s.id] || 'absent',
    }));

    try {
      await api.markClassAttendance(user.id, {
        date,
        attendance: attendanceArray,
      });
      Alert.alert('Success', 'Attendance marked successfully');
    } catch (error: any) {
      console.error('Error marking attendance:', error);
      Alert.alert('Error', error.message || 'Failed to mark attendance');
    }
  }, [user?.id, students, attendance, date]);

  return (
    <>
      <Stack.Screen options={{ title: 'Attendance', headerShown: true }} />
      <View style={{ flex: 1, backgroundColor: colors.backgroundGray }}>
        {/* Tabs */}
        <View style={{ backgroundColor: colors.background, paddingHorizontal: 24, paddingVertical: 12, borderBottomWidth: 1, borderBottomColor: colors.border }}>
          <View style={{ flexDirection: 'row', backgroundColor: colors.backgroundGray, borderRadius: 12, padding: 4 }}>
            <TouchableOpacity
              style={[{ flex: 1, paddingVertical: 12, alignItems: 'center', borderRadius: 10 }, activeTab === 'self' && { backgroundColor: colors.background, shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.1, shadowRadius: 2, elevation: 2 }]}
              onPress={() => setActiveTab('self')}
              accessibilityRole="tab"
              accessibilityLabel="My Attendance"
              accessibilityState={{ selected: activeTab === 'self' }}
            >
              <Text style={[{ fontWeight: '500', fontSize: 14 }, activeTab === 'self' && { fontWeight: '600', color: colors.text }]}>
                My Attendance
              </Text>
            </TouchableOpacity>
            <TouchableOpacity
              style={[{ flex: 1, paddingVertical: 12, alignItems: 'center', borderRadius: 10 }, activeTab === 'class' && { backgroundColor: colors.background, shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.1, shadowRadius: 2, elevation: 2 }]}
              onPress={() => setActiveTab('class')}
              accessibilityRole="tab"
              accessibilityLabel="Class Attendance"
              accessibilityState={{ selected: activeTab === 'class' }}
            >
              <Text style={[{ fontWeight: '500', fontSize: 14, color: colors.textSecondary }, activeTab === 'class' && { fontWeight: '600', color: colors.text }]}>
                Class Attendance
              </Text>
            </TouchableOpacity>
          </View>
        </View>

        {activeTab === 'self' ? (
          <SelfAttendance />
        ) : (
          <ClassAttendance
            students={students}
            attendance={attendance}
            loading={loading}
            onMarkAttendance={markAttendance}
            onSubmit={submitAttendance}
          />
        )}
      </View>
    </>
  );
}

function SelfAttendance() {
  const { colors } = useTheme();
  return (
    <ScrollView style={{ flex: 1 }}>
      <View style={{ margin: 24, padding: 40, backgroundColor: colors.card, borderRadius: 16, alignItems: 'center', shadowColor: '#000', shadowOffset: { width: 0, height: 2 }, shadowOpacity: 0.06, shadowRadius: 8, elevation: 2 }}>
        <View style={{ width: 80, height: 80, borderRadius: 40, backgroundColor: colors.primary + '15', justifyContent: 'center', alignItems: 'center', marginBottom: 16 }}>
          <Ionicons name="calendar-outline" size={48} color={colors.primary} />
        </View>
        <Text style={{ fontSize: 20, fontWeight: '600', color: colors.text, marginBottom: 8 }}>My Attendance Record</Text>
        <Text style={{ fontSize: 15, color: colors.textSecondary, textAlign: 'center' }}>
          Track your attendance history here
        </Text>
      </View>
    </ScrollView>
  );
}

interface ClassAttendanceProps {
  students: any;
  attendance: any;
  loading: boolean;
  onMarkAttendance: (studentId: string, status: string) => void;
  onSubmit: () => void;
}

function ClassAttendance({
  students,
  attendance,
  loading,
  onMarkAttendance,
  onSubmit,
}: ClassAttendanceProps) {
  const { colors } = useTheme();

  if (loading) {
    return (
      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
        <ActivityIndicator size="large" color={colors.primary} />
      </View>
    );
  }

  if (!students || students.students?.length === 0) {
    return (
      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', padding: 24 }}>
        <View style={{ width: 80, height: 80, borderRadius: 40, backgroundColor: colors.backgroundGray, justifyContent: 'center', alignItems: 'center', marginBottom: 16 }}>
          <Ionicons name="people-outline" size={48} color={colors.textSecondary} />
        </View>
        <Text style={{ fontSize: 16, color: colors.textSecondary, textAlign: 'center', marginTop: 16 }}>
          You are not assigned as a class teacher
        </Text>
      </View>
    );
  }

  const presentCount = Object.values(attendance).filter((v: any) => v === 'present').length;
  const absentCount = Object.values(attendance).filter((v: any) => v === 'absent').length;
  const lateCount = Object.values(attendance).filter((v: any) => v === 'late').length;

  return (
    <ScrollView style={{ flex: 1 }}>
      {/* Class Header */}
      <View style={{ margin: 24, marginBottom: 16, padding: 20, backgroundColor: colors.primary, borderRadius: 16 }}>
        <View style={{ marginBottom: 16 }}>
          <Text style={{ fontSize: 22, fontWeight: '700', color: colors.white }}>
            {students.class.name} {students.class.section}
          </Text>
          <Text style={{ fontSize: 15, color: 'rgba(255,255,255,0.8)', marginTop: 4 }}>
            {students.students.length} Students
          </Text>
        </View>
        <View style={{ flexDirection: 'row', backgroundColor: 'rgba(255,255,255,0.15)', borderRadius: 12, padding: 16 }}>
          <View style={{ flex: 1, alignItems: 'center' }}>
            <Text style={{ fontSize: 24, fontWeight: '700', color: colors.success }}>{presentCount}</Text>
            <Text style={{ fontSize: 12, color: 'rgba(255,255,255,0.8)', marginTop: 4, textTransform: 'uppercase', letterSpacing: 0.5 }}>Present</Text>
          </View>
          <View style={{ width: 1, backgroundColor: 'rgba(255,255,255,0.3)' }} />
          <View style={{ flex: 1, alignItems: 'center' }}>
            <Text style={{ fontSize: 24, fontWeight: '700', color: colors.error }}>{absentCount}</Text>
            <Text style={{ fontSize: 12, color: 'rgba(255,255,255,0.8)', marginTop: 4, textTransform: 'uppercase', letterSpacing: 0.5 }}>Absent</Text>
          </View>
          <View style={{ width: 1, backgroundColor: 'rgba(255,255,255,0.3)' }} />
          <View style={{ flex: 1, alignItems: 'center' }}>
            <Text style={{ fontSize: 24, fontWeight: '700', color: '#F5A623' }}>{lateCount}</Text>
            <Text style={{ fontSize: 12, color: 'rgba(255,255,255,0.8)', marginTop: 4, textTransform: 'uppercase', letterSpacing: 0.5 }}>Late</Text>
          </View>
        </View>
      </View>

      {/* Students List */}
      <View style={{ paddingHorizontal: 24 }}>
        <Text style={{ fontSize: 18, fontWeight: '600', color: colors.text, marginBottom: 12 }}>Students</Text>
        {students.students.map((student: any) => (
          <View key={student.id} style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', padding: 16, marginBottom: 12, backgroundColor: colors.card, borderRadius: 16, shadowColor: '#000', shadowOffset: { width: 0, height: 2 }, shadowOpacity: 0.06, shadowRadius: 8, elevation: 2 }}>
            <View style={{ flexDirection: 'row', alignItems: 'center', flex: 1 }}>
              <View style={{ width: 44, height: 44, borderRadius: 22, backgroundColor: colors.backgroundGray, justifyContent: 'center', alignItems: 'center', marginRight: 14 }}>
                <Text style={{ fontSize: 18, fontWeight: '600', color: colors.primary }}>{student.name.charAt(0).toUpperCase()}</Text>
              </View>
              <View>
                <Text style={{ fontSize: 16, fontWeight: '500', color: colors.text }}>{student.name}</Text>
                <Text style={{ fontSize: 13, color: colors.textSecondary, marginTop: 2 }}>Roll No. {student.rollNo}</Text>
              </View>
            </View>
            <View style={{ flexDirection: 'row', gap: 8 }}>
              <TouchableOpacity
                style={[{ width: 40, height: 40, borderRadius: 20, justifyContent: 'center', alignItems: 'center', backgroundColor: colors.backgroundGray }, attendance[student.id] === 'present' && { backgroundColor: colors.success }]}
                onPress={() => onMarkAttendance(student.id, 'present')}
              >
                <Ionicons
                  name="checkmark"
                  size={18}
                  color={attendance[student.id] === 'present' ? colors.white : colors.textSecondary}
                />
              </TouchableOpacity>
              <TouchableOpacity
                style={[{ width: 40, height: 40, borderRadius: 20, justifyContent: 'center', alignItems: 'center', backgroundColor: colors.backgroundGray }, attendance[student.id] === 'absent' && { backgroundColor: colors.error }]}
                onPress={() => onMarkAttendance(student.id, 'absent')}
              >
                <Ionicons
                  name="close"
                  size={18}
                  color={attendance[student.id] === 'absent' ? colors.white : colors.textSecondary}
                />
              </TouchableOpacity>
              <TouchableOpacity
                style={[{ width: 40, height: 40, borderRadius: 20, justifyContent: 'center', alignItems: 'center', backgroundColor: colors.backgroundGray }, attendance[student.id] === 'late' && { backgroundColor: '#F5A623' }]}
                onPress={() => onMarkAttendance(student.id, 'late')}
              >
                <Text
                  style={[{ fontSize: 14, fontWeight: '700', color: colors.textSecondary }, attendance[student.id] === 'late' && { color: colors.white }]}
                >
                  L
                </Text>
              </TouchableOpacity>
            </View>
          </View>
        ))}
      </View>

      <TouchableOpacity style={{ margin: 24, padding: 18, backgroundColor: colors.primary, borderRadius: 12, alignItems: 'center' }} onPress={onSubmit}>
        <Text style={{ color: colors.white, fontSize: 16, fontWeight: '600' }}>Submit Attendance</Text>
      </TouchableOpacity>
      <View style={{ height: 24 }} />
    </ScrollView>
  );
}

