import React, { useEffect, useState, useCallback } from 'react';
import {
  View,
  Text,
  ScrollView,
  StyleSheet,
  ActivityIndicator,
  Alert,
  SafeAreaView,
  StatusBar,
  RefreshControl,
} from 'react-native';
import { useAuth } from '../../context/AuthContext';
import api from '../../services/api';
import { useTheme } from '../../context/ThemeContext';

const DAYS = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];

export default function TimetableScreen() {
  const { user } = useAuth();
  const { colors } = useTheme();
  const [timetable, setTimetable] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  const loadTimetable = useCallback(async () => {
    if (!user?.id) return;
    try {
      const data = await api.getTimetable(user.id);
      setTimetable(data);
    } catch (error) {
      console.error('Error loading timetable:', error);
      Alert.alert('Error', 'Failed to load timetable. Please try again.');
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, [user?.id]);

  useEffect(() => {
    loadTimetable();
  }, [loadTimetable]);

  const onRefresh = useCallback(() => {
    setRefreshing(true);
    loadTimetable();
  }, [loadTimetable]);

  if (loading) {
    return (
      <SafeAreaView style={[styles.centerContainer, { backgroundColor: colors.backgroundGray }]}>
        <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
        <ActivityIndicator size="large" color={colors.primary} />
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={[styles.container, { backgroundColor: colors.backgroundGray }]}>
      <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
      <ScrollView
        refreshControl={
          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} colors={[colors.primary]} tintColor={colors.primary} />
        }
      >
        {DAYS.map((day) => {
          const daySchedule = timetable?.[day] || [];
          return (
            <View
              key={day}
              style={[styles.dayCard, { backgroundColor: colors.background }]}
              accessibilityRole="region"
              accessibilityLabel={`${day} schedule`}
            >
              <Text style={[styles.dayTitle, { color: colors.text }]}>{day}</Text>
              {daySchedule.length > 0 ? (
                daySchedule.map((period: any, index: number) => (
                  <View
                    key={index}
                    style={[
                      styles.periodCard,
                      { backgroundColor: colors.inputBackground, borderLeftColor: colors.primary }
                    ]}
                    accessibilityRole="text"
                    accessibilityLabel={`${period.subject}, Period ${period.periodIndex}${period.room ? `, Room ${period.room}` : ''}${period.classId ? `, for Class ${period.classId.name} ${period.classId.section}` : ''}`}
                  >
                    <View style={styles.periodHeader}>
                      <Text style={[styles.periodNumber, { color: colors.primary }]}>{period.subject}</Text>
                      {period.room && (
                        <Text style={[styles.roomText, { color: colors.textSecondary }]}>Period {period.periodIndex} • Room: {period.room}</Text>
                      )}
                    </View>
                    {period.classId && (
                      <Text style={[styles.classText, { color: colors.textSecondary }]}>
                        Class {period.classId.name} {period.classId.section}
                      </Text>
                    )}
                  </View>
                ))
              ) : (
                <Text style={[styles.noClassesText, { color: colors.textSecondary }]}>No classes scheduled</Text>
              )}
            </View>
          );
        })}
        <View style={{ height: 24 }} />
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
  centerContainer: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
  dayCard: {
    marginHorizontal: 16,
    marginVertical: 8,
    padding: 16,
    borderRadius: 16,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.08,
    shadowRadius: 8,
    elevation: 2,
  },
  dayTitle: {
    fontSize: 20,
    fontWeight: '700',
    marginBottom: 16,
  },
  periodCard: {
    padding: 14,
    marginBottom: 10,
    borderRadius: 12,
    borderLeftWidth: 4,
  },
  periodHeader: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: 6,
  },
  periodNumber: {
    fontSize: 16,
    fontWeight: '700',
  },
  roomText: {
    fontSize: 13,
    fontWeight: '500',
  },
  subjectText: {
    fontSize: 15,
    fontWeight: '600',
    marginBottom: 4,
  },
  classText: {
    fontSize: 13,
  },
  noClassesText: {
    fontStyle: 'italic',
    padding: 12,
    textAlign: 'center',
  },
});

